class Solution(object):
    def countAlternatingSubarrays(self, nums):
        ans = 1
        run = 1
        for i in range(1, len(nums)):
            if nums[i] != nums[i - 1]:
                run += 1
            else:
                run = 1
            ans += run
        return ans
